#!/bin/bash
dfx start --background
dfx identity use MOPS
dfx deploy icrc2_ledger --argument '(
  variant {
    Init = record {
      decimals = opt (8 : nat8);
      token_symbol = "NXT";
      transfer_fee = 1_000_000 : nat;
      metadata = vec {
        record {
          "icrc1:logo";
          variant {
          Text = "data:image/svg+xml;base64,"          };
        };
      };
      minting_account = record {
        owner = principal "l4zq2-cqaaa-aaaap-qumea-cai";
        subaccount = opt blob "minter00000000000000000000000000";
      };
      initial_balances = vec {};
      fee_collector_account = opt record {
        owner = principal "l4zq2-cqaaa-aaaap-qumea-cai";
        subaccount = opt blob "feecollector00000000000000000000";
      };
      archive_options = record {
        num_blocks_to_archive = 1_000 : nat64;
        max_transactions_per_response = null;
        trigger_threshold = 2_000 : nat64;
        more_controller_ids = null;
        max_message_size_bytes = null;
        cycles_for_archive_creation = opt (10_000_000_000_000 : nat64);
        node_max_memory_size_bytes = null;
        controller_id = principal "52s67-fcrml-vgrfn-p3fb6-pyegc-oxdcx-4adgz-alqhq-ai5up-acahq-jae"
      };
      max_memo_length = opt (80 : nat16);
      index_principal = null;
      token_name = "Nexus Token";
      feature_flags = opt record { icrc2 = true };
    }
  }
)'
